import javax.inject._
import play.api._
import play.api.mvc._
import scala.io.Source

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def serveFile(path: String) = Action { implicit request: Request[AnyContent] =>
    try {
      val fileContents = Source.fromFile(s"uploads/$path").mkString
      Ok(fileContents)
    } catch {
      case ex: Exception =>
        NotFound(s"Could not find file: $path")
    }
  }
}